const isIndicatorWithinDomain = (
  start: number,
  end: number,
  domainStart: number,
  domainEnd: number,
) => start >= domainStart && end <= domainEnd;

const isIndicatorPartiallyWithinDomain = (
  start: number,
  end: number,
  domainStart: number,
  domainEnd: number,
) => start <= domainEnd && end >= domainStart;

export const isIndicatorPartiallyOrWithinDomain = (
  start: number,
  end: number,
  domainStart: number,
  domainEnd: number,
) =>
  isIndicatorWithinDomain(start, end, domainStart, domainEnd) ||
  isIndicatorPartiallyWithinDomain(start, end, domainStart, domainEnd);
